import {useState, type JSXElementConstructor, type ReactElement, type ReactNode, type ReactPortal} from 'react';
import {SelectButton} from "primereact/selectbutton";
import ar from '../../../assets/Images/flags/sa.jpg'
import en from '../../../assets/Images/flags/uk.png'
import {useLanguage} from "../../../_compat";
import {Flex, Text} from "../../../_compat";
import './index.scss'

const LanguageSwitcher = () => {
    const {currentLanguage, changeLanguage} = useLanguage()

    const options = [
        {
            img: ar,
            // text: 'AR',
            value: 'ar'
        },
        {
            img: en,
            // text: 'EN',
            value: 'en'
        }
    ];

    const [value, setValue] = useState(currentLanguage);

    const justifyTemplate = (option: { text: string | number | bigint | boolean | ReactElement<unknown, string | JSXElementConstructor<any>> | Iterable<ReactNode> | ReactPortal | Promise<string | number | bigint | boolean | ReactPortal | ReactElement<unknown, string | JSXElementConstructor<any>> | Iterable<ReactNode> | null | undefined> | null | undefined; img: string | undefined; }) => {

        return (
            <Flex gap={5} justifyContent={"center"} alignItems={"center"} className={'sm'}>
                <Text fontSize={'14px'}>{option.text}</Text>
                <img src={option.img} width={30} height={15} alt={""}/>
            </Flex>
        );
    }

    return (
        <SelectButton
            value={value}
            className={'langSwitcher'}
            onChange={(e) => {
                setValue(e.value)
                changeLanguage(e.value)
            }}
            itemTemplate={justifyTemplate}
            options={options}
        />
    );
};

export default LanguageSwitcher;
